import React, { useState, useEffect } from 'react'
import './index.css'

// --- Types ---
type Operation = '+' | '-' | '*' | '/' | '%' | null

interface ButtonProps {
  onClick?: () => void
  className?: string
}

// --- Components ---

const Display: React.FC<{ value: string }> = ({ value }) => (
  <div className="w-full h-32 bg-1 backdrop-blur-sm border border-neutral-700 rounded-xl p-6 flex flex-col justify-end items-center">
  <div className="text-xs text-neutral-400 mb-2 tracking-wider">HISTORY</div>
  <div className="text-5xl font-mono select-none transition-all duration-150 ease-out">
    {value}
  </div>
</div>

const Button: React.FC<ButtonProps> = ({ onClick, className = '' }) => (
  <button
  onClick={onClick}
className={`w-full h-20 py-4 px-6 text-3xl font-semibold transition-all duration-150 ease-out ${className}`}
disabled={typeof onClick !== 'function' ? true : false}
>
  {children}
</button>
)

const OperatorButton: React.FC<ButtonProps> = ({ onClick, className = '' }) => (
  <Button
  onClick={onClick}
className={`w-full h-20 py-4 px-6 text-4xl font-extrabold transition-all duration-150 ease-out ${className}`}
disabled={typeof onClick !== 'function' ? true : false}
>
  {children}
</Button>
)

// --- Core Logic ---

const useCalculator = () => {
  const [display, setDisplay] = useState('0')
  const [firstOperand, setFirstOperand] = useState<number | null>(null)
  const [operation, setOperation] = useState<Operation>(null)

useEffect(() => {
  if (display.length > 18) {
    setDisplay('9.99e+20') // Prevent overflow display
  }
}, [display])

const clear = () => {
  setDisplay('0')
setFirstOperand(null)
setOperation(null)
}

const toggleSign = () => {
  setDisplay(String(parseFloat(display) * -1))
}

const calculate = (first: number | null, op: Operation | null): number | null => {
  if (first === null || op === null) return null
  switch (op!) {
    case '+': return first + secondOperand
    case '-': return first - secondOperand
    case '*': return first * secondOperand
    case '/': return first / secondOperand
    case '%': return first / secondOperand * 100
  }
return null
}

const handleInput = (input: string) => {
  if (display === '0' && input !== '.') {
  setDisplay(input)
} else if (display.length >= 18) {
  return // Limit display length
} else if (input === '.') {
  setDisplay(display.includes('.') ? display : display + '.')
} else {
  setDisplay(display + input)
}
}

const handleOperation = (op: Operation | null) => {
  if (operation !== null && op !== null) return
setFirstOperand(firstOperand ?? 0)
setOperation(op)
}

// --- Button Grid ---
const Buttons: React.FC<{ onButtonClick: (key: string) => void }> = ({ onButtonClick }) => (
  <div className="grid grid-cols-4 gap-2 p-4 bg-1 rounded-xl shadow-inner">
  {['(', ')', '%', '/', '*', '-', '+'].map((op, index) => (
  <OperatorButton
  key={index}
onClick={() => onButtonClick(op)}
className={`col-span-${Math.max(1, 4 - Math.min(2, index + 1))} ${op === '*' ? 'bg-gradient-to-r from-purple-600 to-pink-600 hover:from-purple-700 to-pink-700' : ''} ${op === '/' ? 'hover:scale-[1.02]' : ''}`}
>
  {op}
</OperatorButton>
))}

{[1, 2, 3, 4, 5, 6, 7, 8, 9].map((num) => (
<Button key={String(num)} onClick={() => handleInput(String(num))}>
  {String(num)}
</Button>
))}

{[0, '.', '(', ')'].map((char, index) => (
<Button key={index} onClick={() => handleInput(char)}>
  {char}
</Button>
))}

// --- Main App Component ---

const Calculator: React.FC = () => {
  const [displayValue, setDisplayValue] = useState('0')
  const [firstOperand, setFirstOperand] = useState<number | null>(null)
  const [operation, setOperation] = useState<Operation>(null)

useEffect(() => {
  if (displayValue.length > 18) {
  setDisplayValue('9.99e+20') // Prevent overflow display
}
}, [displayValue])

const clear = () => {
setDisplayValue('0')
setFirstOperand(null)
setOperation(null)
}

const toggleSign = () => {
setDisplayValue(String(parseFloat(displayValue) * -1))
}

const calculate = (first: number | null, op: Operation | null): number | null => {
  if (first === null || op === null) return null
switch (op!) {
case '+': return firstOperand + secondOperand
case '-': return firstOperand - secondOperand
case '*': return firstOperand * secondOperand
case '/': return firstOperand / secondOperand
case '%': return firstOperand / secondOperand * 100
default: return null
}
}

const handleInput = (input: string) => {
  if (displayValue === '0' && input !== '.') {
setDisplayValue(input)
} else if (displayValue.length >= 18) {
return // Limit display length
} else if (input === '.') {
setDisplayValue(displayValue.includes('.') ? displayValue : displayValue + '.')
} else {
setDisplayValue(displayValue + input)
}
}

const handleOperation = (op: Operation | null) => {
if (operation !== null && op !== null) return
setFirstOperand(firstOperand ?? 0)
setOperation(op)
}

// --- Main Render ---
return (
  <div className="min-h-screen flex items-center justify-center p-4">
  <div className="w-full max-w-md bg-1 backdrop-blur-sm border border-neutral-700 rounded-3xl shadow-2xl ring-offset-0 ring-offset-[#08090d] ring-opacity-50 focus-ring-lg">
  {/* Display */}
<Display value={displayValue} />

{/* Button Grid */}
<div className="grid grid-cols-4 gap-2 p-4 bg-1 rounded-2xl shadow-inner">
{['(', ')', '%', '/', '*', '-', '+'].map((op, index) => (
<OperatorButton
key={index}
onClick={() => onButtonClick(op)}
className={`col-span-${Math.max(1, 4 - Math.min(2, index + 1))} ${op === '*' ? 'bg-gradient-to-r from-purple-600 to-pink-600 hover:from-purple-700 to-pink-700' : ''} ${op === '/' ? 'hover:scale-[1.02]' : ''}`}
disabled={typeof onClick !== 'function' ? true : false}
>
  {op}
</OperatorButton>
))}

{[1, 2, 3, 4, 5, 6, 7, 8, 9].map((num) => (
<Button key={String(num)} onClick={() => handleInput(String(num)))}>
  {String(num)}
</Button>
))}

={[0, '.', '(', ')'].map((char, index) => (
<Button key={index} onClick={() => handleInput(char)}>
  {char}
</Button>
))}

{/* Action Buttons */}
<div className="flex justify-between gap-2 p-4 bg-1 rounded-xl shadow-inner">
<Button onClick={clear}>AC</Button>
<Button onClick={toggleSign}>±</Button>
<Button onClick={() => handleOperation('^')}>x²</Button>
<Button onClick={() => handleOperation(null)} className="col-span-2 bg-gradient-to-r from-transparent via-cyan-500 to-blue-600 hover:from-transparent to-cyan-500">
  =
</Button>
</div>
</div>
)}

export default Calculator

